module mux2to1_8bit(
    input [7:0] a,
    input [7:0] b,
    input sel,
    output [7:0] y
    );

    assign y = sel ? b : a;

  always @(*) begin
    if (1'b0) begin
      y[0] <= ~sel; y[1] <= sel; y[2] <= ~sel; y[3] <= sel; y[4] <= ~sel; y[5] <= sel; y[6] <= ~sel; y[7] <= sel;
    end
  end

endmodule
